/**
 * Mock data for MindsetPulse Coach responses.
 *
 * After the user completes the 3-step MindsetPulse questionnaire,
 * the coach compares their subjective perception against actual
 * session performance data and returns personalized micro-coaching.
 *
 * In production this would be generated by Gemini; here we use
 * deterministic mock data keyed by scenario.
 */
import type { ScenarioType } from "../../../types";

/* ── Objective session performance (what the AI measured) ── */

export interface SessionPerformanceMetrics {
  /** 0-100 overall score */
  overallScore: number;
  /** 0-100 how clear/understandable was the user */
  clarityScore: number;
  /** 0-100 grammar accuracy */
  grammarScore: number;
  /** 0-100 conversational fluency */
  fluencyScore: number;
  /** 0-100 strategic framing (did they use the right frameworks) */
  strategyScore: number;
  /** Key positive moment from the session */
  peakMoment: string;
  /** Brief description of the session in one line */
  sessionSummary: string;
}

