/* ── Perception Gap coaching (Liking Gap) ── */

interface PerceptionGapInsight {
  /** Headline for the gap */
  headline: string;
  /** Explanatory paragraph */
  body: string;
  /** Name of the psychological concept */
  concept: string;
}

/**
 * Returns a perception gap insight based on the difference between
 * self-assessment (1-5) and actual performance (0-100).
 *
 * The "normalized self" maps 1-5 to roughly 20-100:
 *   1→20, 2→40, 3→60, 4→80, 5→100
 */
function getPerceptionGap(
  selfAssessment: number,
  actualScore: number
): PerceptionGapInsight {
  const normalizedSelf = selfAssessment * 20;
  const gap = actualScore - normalizedSelf;

  if (gap >= 15) {
    // User underestimates themselves significantly
    return {
      headline: "Te subestimas — y eso es completamente normal",
      body: `Tu auto-evaluación fue ${selfAssessment}/5, pero tu desempeño real fue ${actualScore}/100. Esta brecha se llama el "Liking Gap": las personas consistentemente creen que su impacto fue menor de lo que realmente fue. En tu caso, la diferencia es de ${gap} puntos. Tu próximo objetivo no es mejorar tu inglés — es confiar en el que ya tienes.`,
      concept: "Liking Gap",
    };
  } else if (gap >= 5) {
    // Slight underestimation
    return {
      headline: "Tu percepción está casi calibrada — con un ligero sesgo",
      body: `Evaluaste tu desempeño en ${selfAssessment}/5 y obtuviste ${actualScore}/100. Estás cerca, pero aún subestimas ligeramente tu capacidad. Esto es común en profesionales LATAM que operan en inglés — la exigencia cultural es alta. Reconoce que lo estás haciendo bien.`,
      concept: "Sesgo de autoexigencia",
    };
  } else if (gap >= -10) {
    // Well calibrated
    return {
      headline: "Tu autopercepción está bien calibrada",
      body: `Evaluaste tu desempeño en ${selfAssessment}/5 y obtuviste ${actualScore}/100. Esa alineación entre percepción y realidad es una fortaleza ejecutiva. Significa que puedes confiar en tu instinto para saber cuándo estás comunicando efectivamente.`,
      concept: "Metacognición precisa",
    };
  } else {
    // User overestimates
    return {
      headline: "Tu confianza supera tu ejecución actual — y eso tiene valor",
      body: `Evaluaste tu desempeño en ${selfAssessment}/5 pero obtuviste ${actualScore}/100. Esa confianza es un activo — úsala como combustible para practicar las áreas técnicas. Las personas seguras que además son precisas son imparables.`,
      concept: "Confianza como catalizador",
    };
  }
}

/* ── Confidence-specific nudge ── */

function getConfidenceNudge(
  confidenceLevel: number,
  actualScore: number
): string {
  if (confidenceLevel <= 2 && actualScore >= 65) {
    return "Sentiste inseguridad, pero tu desempeño dice otra cosa. Esa brecha entre cómo te sientes y cómo te perciben es exactamente lo que el Liking Gap predice. Con cada sesión, esa brecha se cierra.";
  }
  if (confidenceLevel <= 2 && actualScore < 65) {
    return "Es normal sentir inseguridad cuando estás construyendo una nueva habilidad. Lo importante: completaste la sesión. Cada minuto de práctica está recableando tu cerebro para el inglés ejecutivo.";
  }
  if (confidenceLevel >= 4 && actualScore >= 75) {
    return "Tu confianza alta coincide con un desempeño sólido. Estás en el punto donde puedes empezar a tomar riesgos comunicativos — frases más complejas, opiniones más directas.";
  }
  if (confidenceLevel >= 4 && actualScore < 65) {
    return "Tu confianza es un activo enorme. Ahora canalízala hacia áreas específicas: gramática bajo presión y fluidez en respuestas espontáneas. La confianza + precisión es la combinación ganadora.";
  }
  // Middle confidence
  return "Un nivel de confianza moderado es saludable — significa que eres consciente de dónde estás y hacia dónde vas. Tu próxima sesión es una oportunidad de subir un punto.";
}

/* ── Public API ── */

export interface MindsetCoachingResponse {
  perceptionGap: PerceptionGapInsight;
  fearCoaching: FearCoaching;
  confidenceNudge: string;
  metrics: SessionPerformanceMetrics;
  /** A single takeaway sentence the user should remember */
  takeaway: string;
}

/**
 * Generates a personalized coaching response based on the user's
 * MindsetPulse answers and the session's objective metrics.
 */
export function generateMindsetCoaching(
  scenarioType: ScenarioType | undefined,
  pulse: {
    confidenceLevel: number;
    biggestFear: string;
    selfAssessment: number;
  }
): MindsetCoachingResponse {
  const scenario = scenarioType || "sales";
  const metrics =
    METRICS_BY_SCENARIO[scenario] || METRICS_BY_SCENARIO["sales"];

  const perceptionGap = getPerceptionGap(
    pulse.selfAssessment,
    metrics.overallScore
  );

  // Replace placeholders in fear coaching
  const rawFear = FEAR_COACHING[pulse.biggestFear] || FEAR_COACHING["none"];
  const fearCoaching: FearCoaching = {
    validation: rawFear.validation,
    insight: rawFear.insight
      .replace("{clarityScore}", String(metrics.clarityScore))
      .replace("{fluencyScore}", String(metrics.fluencyScore))
      .replace("{strategyScore}", String(metrics.strategyScore))
      .replace("{grammarScore}", String(metrics.grammarScore)),
    action: rawFear.action,
  };

  const confidenceNudge = getConfidenceNudge(
    pulse.confidenceLevel,
    metrics.overallScore
  );

  // Generate takeaway based on the biggest gap
  const takeaway = generateTakeaway(pulse, metrics);

  return {
    perceptionGap,
    fearCoaching,
    confidenceNudge,
    metrics,
    takeaway,
  };
}

function generateTakeaway(
  pulse: { confidenceLevel: number; biggestFear: string; selfAssessment: number },
  metrics: SessionPerformanceMetrics
): string {
  const normalizedSelf = pulse.selfAssessment * 20;
  const gap = metrics.overallScore - normalizedSelf;

  if (gap >= 15) {
    return "Tu inglés ejecutivo ya es más fuerte de lo que crees. La próxima vez que dudes, recuerda este número.";
  }
  if (pulse.confidenceLevel <= 2) {
    return "La inseguridad que sientes no es falta de habilidad — es falta de evidencia. Cada sesión te da más evidencia.";
  }
  if (metrics.overallScore >= 75) {
    return "Estás en el nivel donde los detalles marcan la diferencia. Enfócate en pulir, no en reconstruir.";
  }
  return "Cada sesión es un paso. No necesitas ser perfecto — necesitas ser consistente. Nos vemos mañana.";
}

/** Convenience: get metrics only (for components that need scores without coaching) */
export function getSessionMetricsForScenario(
  scenarioType: ScenarioType | undefined
): SessionPerformanceMetrics {
  const scenario = scenarioType || "sales";
  return METRICS_BY_SCENARIO[scenario] || METRICS_BY_SCENARIO["sales"];
}
